import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVFormat.Predefined;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

public class CSVFormatTest {

    @Test
    public void testValueOf_withValidPredefinedFormat() {
        try (MockedStatic<CSVFormat.Predefined> mockedPredefined = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            CSVFormat expectedFormat = CSVFormat.DEFAULT;
            mockedPredefined.when(() -> CSVFormat.Predefined.valueOf("DEFAULT")).thenReturn(new CSVFormat.Predefined() {
                @Override
                public CSVFormat getFormat() {
                    return expectedFormat;
                }
            });

            CSVFormat actual = CSVFormat.valueOf("DEFAULT");
            assertNotNull(actual);
            assertEquals(expectedFormat, actual);
        }
    }

    @Test
    public void testValueOf_withNullFormatString() {
        try (MockedStatic<CSVFormat.Predefined> mockedPredefined = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            mockedPredefined.when(() -> CSVFormat.Predefined.valueOf(null)).thenThrow(NullPointerException.class);
            assertThrows(NullPointerException.class, () -> CSVFormat.valueOf(null));
        }
    }

    @Test
    public void testValueOf_withUnknownFormatString() {
        try (MockedStatic<CSVFormat.Predefined> mockedPredefined = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            mockedPredefined.when(() -> CSVFormat.Predefined.valueOf("UNKNOWN")).thenThrow(IllegalArgumentException.class);
            assertThrows(IllegalArgumentException.class, () -> CSVFormat.valueOf("UNKNOWN"));
        }
    }
}
